// REPLACE your current Hero Banner section with this:

{/* 2. PREMIUM DYNAMIC HERO BANNER */}
<div style={{ 
  width: '100%', 
  height: '220px', // Slightly taller for more impact
  position: 'relative', 
  overflow: 'hidden', 
  backgroundColor: '#111' 
}}>
  {slides.map((slide, index) => (
    <div key={index} style={{ 
      position: 'absolute', 
      top: 0, left: 0, 
      width: '100%', height: '100%', 
      opacity: index === currentSlide ? 1 : 0, 
      transition: 'opacity 1.2s ease-in-out', 
      display: 'flex', 
      flexDirection: 'column', 
      justifyContent: 'center', 
      padding: '0 30px',
      // IMAGE LOGIC
      backgroundImage: `url(${slide.bgImage})`,
      backgroundSize: 'cover',
      backgroundPosition: 'center',
    }}>
      {/* DARK GRADIENT OVERLAY - Makes the text pop regardless of the photo */}
      <div style={{
        position: 'absolute',
        top: 0, left: 0,
        width: '100%', height: '100%',
        background: 'linear-gradient(to right, rgba(0,0,0,0.8) 0%, rgba(0,0,0,0.2) 100%)',
        zIndex: 1
      }}></div>

      {/* TEXT CONTENT */}
      <div style={{ position: 'relative', zIndex: 2 }}>
        <h2 style={{ 
          fontSize: '2.2rem', 
          color: '#fff', 
          fontWeight: '900', 
          margin: 0, 
          letterSpacing: '1.5px', 
          textTransform: 'uppercase',
          textShadow: '2px 2px 10px rgba(0,0,0,0.5)'
        }}>
          {slide.title}
        </h2>
        <p style={{ 
          fontSize: '1.2rem', 
          color: softCream, 
          margin: '10px 0 0', 
          fontWeight: '500',
          opacity: 0.9 
        }}>
          {slide.subtitle}
        </p>
      </div>
    </div>
  ))}
</div>
